package com.zorvyn.financebackend.model;import com.zorvyn.financebackend.enums.RecordType;import jakarta.persistence.Column;import jakarta.persistence.Entity;import jakarta.persistence.EnumType;import jakarta.persistence.Enumerated;import jakarta.persistence.GeneratedValue;import jakarta.persistence.GenerationType;import jakarta.persistence.Id;import jakarta.persistence.Table;import java.math.BigDecimal;import java.time.LocalDate;import java.time.OffsetDateTime;@Entity@Table(name = "financial_records")public class FinancialRecord {    @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    @Column(nullable = false, precision = 14, scale = 2)    private BigDecimal amount;    @Enumerated(EnumType.STRING)    @Column(nullable = false)    private RecordType type;    @Column(nullable = false)    private String category;    @Column(nullable = false)    private LocalDate recordDate;    @Column(length = 500)    private String notes;    @Column(nullable = false)    private OffsetDateTime createdAt;    @Column(nullable = false)    private OffsetDateTime updatedAt;    public Long getId() {        return id;    }    public void setId(Long id) {        this.id = id;    }    public BigDecimal getAmount() {        return amount;    }    public void setAmount(BigDecimal amount) {        this.amount = amount;    }    public RecordType getType() {        return type;    }    public void setType(RecordType type) {        this.type = type;    }    public String getCategory() {        return category;    }    public void setCategory(String category) {        this.category = category;    }    public LocalDate getRecordDate() {        return recordDate;    }    public void setRecordDate(LocalDate recordDate) {        this.recordDate = recordDate;    }    public String getNotes() {        return notes;    }    public void setNotes(String notes) {        this.notes = notes;    }    public OffsetDateTime getCreatedAt() {        return createdAt;    }    public void setCreatedAt(OffsetDateTime createdAt) {        this.createdAt = createdAt;    }    public OffsetDateTime getUpdatedAt() {        return updatedAt;    }    public void setUpdatedAt(OffsetDateTime updatedAt) {        this.updatedAt = updatedAt;    }}